     2|import { Command, type CommandDefinition } from '../utils/command.js';
     3|import type { CLIOptions, CommandResult, CommandContext, ProjectSnapshot } from '../types/index.js';
     4|import { readFileSync, readdirSync, lstatSync, existsSync } from 'fs';
     5|import { join, relative, basename } from 'path';
     6|import ignore from 'ignore';
     7|
     8|export class PackCommand extends Command {
     9|  readonly definition: CommandDefinition = {
    10|    name: 'pack',
    11|    description: 'Create a snapshot from a local directory',
    12|    usage: 'jref pack [directory] [options]',
    13|    examples: [
    14|      'jref pack . > snapshot.json',
    15|      'jref pack ./my-project --instruction "Follow these rules" > snapshot.json'
    16|    ]
    17|  };
    18|
    19|  async execute(
    20|    args: string[],
    21|    options: CLIOptions,
    22|    _context: CommandContext
    23|  ): Promise<CommandResult> {
    24|    try {
    25|      const { flags, targetDir } = this.parseArgs(args);
    26|      const rootDir = targetDir || process.cwd();
    27|
    28|      if (!existsSync(rootDir)) {
    29|        return this.error(`Directory not found: ${rootDir}`, options);
    30|      }
    31|
    32|      const files: Record<string, string> = {};
    33|      const ig = ignore();
    34|
    35|      // Load .gitignore if it exists
    36|      const gitignorePath = join(rootDir, '.gitignore');
    37|      if (existsSync(gitignorePath)) {
    38|        ig.add(readFileSync(gitignorePath, 'utf8'));
    39|      }
    40|      
    41|      // Always ignore .git
    42|      ig.add('.git');
    43|
    44|      const treeLines: string[] = [basename(rootDir) + '/'];
    45|      this.walk(rootDir, rootDir, ig, files, treeLines, '');
    46|
    47|      const snapshot: ProjectSnapshot = {
    48|        directoryStructure: treeLines.join('\n'),
    49|        files,
    50|        instruction: (flags.instruction as string) || undefined,
    51|        fileSummary: (flags.summary as string) || undefined
    52|      };
    53|
    54|      const output = JSON.stringify(snapshot, null, 2);
    55|      
    56|      // If --json flag is set or silent, we don't print decoration
    57|      if (options.json || options.silent) {
    58|        return this.success(output);
    59|      }
    60|
    61|      console.log(output);
    62|      return this.success(output);
    63|
    64|    } catch (err) {
    65|      return this.error(`Pack failed: ${(err as Error).message}`, options);
    66|    }
    67|  }
    68|
    69|  private walk(
    70|    currentDir: string,
    71|    rootDir: string,
    72|    ig: any,
    73|    files: Record<string, string>,
    74|    treeLines: string[],
    75|    prefix: string
    76|  ): void {
    77|    const entries = readdirSync(currentDir).sort();
    78|    
    79|    entries.forEach((entry, index) => {
    80|      const fullPath = join(currentDir, entry);
    81|      const relPath = relative(rootDir, fullPath);
    82|
    83|      if (ig.ignores(relPath)) return;
    84|
    85|      const isLast = index === entries.length - 1;
    86|      const stats = lstatSync(fullPath);
    87|      const isDir = stats.isDirectory();
    88|
    89|      // Add to tree
    90|      treeLines.push(`${prefix}${isLast ? '└── ' : '├── '}${entry}${isDir ? '/' : ''}`);
    91|
    92|      if (isDir) {
    93|        this.walk(fullPath, rootDir, ig, files, treeLines, prefix + (isLast ? '    ' : '│   '));
    94|      } else {
    95|        files[relPath] = readFileSync(fullPath, 'utf8');
    96|      }
    97|    });
    98|  }
    99|
   100|  protected parseArgs(args: string[]): { flags: Record<string, unknown>; targetDir?: string } {
   101|    const flags: Record<string, unknown> = {};
   102|    let targetDir: string | undefined;
   103|
   104|    for (let i = 0; i < args.length; i++) {
   105|      const arg = args[i];
   106|      if (arg === '--instruction') {
   107|        flags.instruction = args[++i];
   108|      } else if (arg === '--summary') {
   109|        flags.summary = args[++i];
   110|      } else if (!arg.startsWith('-')) {
   111|        targetDir = arg;
   112|      }
   113|    }
   114|
   115|    return { flags, targetDir };
   116|  }
