     2| * Inspect Command
     3| * Views directoryStructure and metadata without loading entire file into memory
     4| * Supports streaming for large JSON snapshots
     5| */
     6|
     7|import { Command, type CommandDefinition } from '../utils/command.js';
     8|import type { CLIOptions, CommandResult, CommandContext, SnapshotMetadata } from '../types/index.js';
     9|import { loadSnapshot, calculateMetadata } from '../utils/streaming-json.js';
    10|import { printTable, printHeader } from '../utils/output.js';
    11|
    12|export class InspectCommand extends Command {
    13|  readonly definition: CommandDefinition = {
    14|    name: 'inspect',
    15|    description: 'View directoryStructure and metadata without loading entire file',
    16|    usage: 'jref inspect [options] [file]',
    17|    examples: [
    18|      'jref inspect snapshot.json',
    19|      'jref inspect --metadata snapshot.json',
    20|      'jref inspect --structure snapshot.json',
    21|      'cat snapshot.json | jref inspect',
    22|      'jref inspect --json snapshot.json'
    23|    ]
    24|  };
    25|
    26|  async execute(
    27|    args: string[],
    28|    options: CLIOptions,
    29|    context: CommandContext
    30|  ): Promise<CommandResult> {
    31|    try {
    32|      const { flags, filePath } = this.parseArgs(args);
    33|
    34|      // Load snapshot from file or stdin
    35|      const snapshot = await loadSnapshot(
    36|        filePath ? await this.readFile(filePath) : context.stdin
    37|      );
    38|
    39|      const metadata = calculateMetadata(snapshot);
    40|
    41|      // Show header in human mode
    42|      if (!options.silent && !options.raw && !options.json) {
    43|        printHeader(options);
    44|      }
    45|
    46|      // Determine what to show
    47|      const showMeta = (flags.metadata as boolean) || false;
    48|      const showStructure = (flags.structure as boolean) || false;
    49|      const showFiles = (flags.files as boolean) || false;
    50|      const showSummary = (flags.summary as boolean) || false;
    51|
    52|      // If no specific flags, show everything
    53|      const showAll = !showMeta && !showStructure && !showFiles && !showSummary;
    54|
    55|      if (options.json) {
    56|        const result: Record<string, unknown> = {};
    57|
    58|        if (showAll || showMeta) {
    59|          result.metadata = metadata;
    60|        }
    61|        if (showAll || showStructure) {
    62|          result.directoryStructure = snapshot.directoryStructure;
    63|        }
    64|        if (showAll || showFiles) {
    65|          result.filePaths = Object.keys(snapshot.files);
    66|        }
    67|        if (showAll || showSummary) {
    68|          if (snapshot.instruction) result.instruction = snapshot.instruction;
    69|          if (snapshot.fileSummary) result.fileSummary = snapshot.fileSummary;
    70|          if (snapshot.userProvidedHeader) result.userProvidedHeader = snapshot.userProvidedHeader;
    71|        }
    72|
    73|        this.print(result, options);
    74|      } else {
    75|        // Human-readable output
    76|        if (showAll || showMeta) {
    77|          this.printMetadata(metadata, options);
    78|        }
    79|        if (showAll || showStructure) {
    80|          this.printStructure(snapshot.directoryStructure, options);
    81|        }
    82|        if (showAll || showFiles) {
    83|          this.printFileList(snapshot, options);
    84|        }
    85|        if (showAll || showSummary) {
    86|          this.printSummary(snapshot, options);
    87|        }
    88|      }
    89|
    90|      return this.success();
    91|    } catch (err) {
    92|      return this.error(`Inspect failed: ${(err as Error).message}`, options);
    93|    }
    94|  }
    95|
    96|  protected parseArgs(args: string[]): { flags: Record<string, unknown>; filePath?: string } {
    97|    const flags: Record<string, unknown> = {};
    98|    let filePath: string | undefined;
    99|
   100|    for (let i = 0; i < args.length; i++) {
   101|      const arg = args[i];
   102|      switch (arg) {
   103|        case '--metadata':
   104|        case '-m':
   105|          flags.metadata = true;
   106|          break;
   107|        case '--structure':
   108|        case '-s':
   109|          flags.structure = true;
   110|          break;
   111|        case '--files':
   112|        case '-f':
   113|          flags.files = true;
   114|          break;
   115|        case '--summary':
   116|          flags.summary = true;
   117|          break;
   118|        default:
   119|          if (!arg.startsWith('-')) {
   120|            filePath = arg;
   121|          }
   122|      }
   123|    }
   124|
   125|    return { flags, filePath };
   126|  }
   127|
   128|  private async readFile(filePath: string): Promise<string> {
   129|    const { readFileSync } = await import('fs');
   130|    return readFileSync(filePath, 'utf8');
   131|  }
   132|
   133|  private printMetadata(metadata: SnapshotMetadata, options: CLIOptions): void {
   134|    if (options.json) {
   135|      this.print(metadata, options);
   136|      return;
   137|    }
   138|
   139|    console.log('\n📊 SNAPSHOT METADATA');
   140|    console.log('─'.repeat(40));
   141|    printTable(
   142|      ['Property', 'Value'],
   143|      [
   144|        ['Files', metadata.fileCount.toString()],
   145|        ['Total Size', this.formatBytes(metadata.totalSize)],
   146|        ['Directory Structure Lines', metadata.directoryStructureLines.toString()],
   147|        ['Has Instructions', metadata.hasInstruction ? 'Yes' : 'No'],
   148|        ['Has File Summary', metadata.hasFileSummary ? 'Yes' : 'No'],
   149|        ['Has Custom Header', metadata.hasUserProvidedHeader ? 'Yes' : 'No']
   150|      ],
   151|      options
   152|    );
   153|    console.log();
   154|  }
   155|
   156|  private printStructure(structure: string, options: CLIOptions): void {
   157|    if (options.json) {
   158|      this.print({ directoryStructure: structure }, options);
   159|      return;
   160|    }
   161|
   162|    console.log('\n📁 DIRECTORY STRUCTURE');
   163|    console.log('─'.repeat(40));
   164|    console.log(structure || '(empty)');
   165|    console.log();
   166|  }
   167|
   168|  private printFileList(snapshot: { files: Record<string, string> }, options: CLIOptions): void {
   169|    const files = Object.keys(snapshot.files);
   170|
   171|    if (options.json) {
   172|      this.print({ filePaths: files }, options);
   173|      return;
   174|    }
   175|
   176|    console.log('\n📄 FILES');
   177|    console.log('─'.repeat(40));
   178|
   179|    if (files.length === 0) {
   180|      console.log('(no files)');
   181|    } else {
   182|      const fileData = files.map((f) => [
   183|        f,
   184|        this.formatBytes(Buffer.byteLength(snapshot.files[f], 'utf8'))
   185|      ]);
   186|      printTable(['Path', 'Size'], fileData, options);
   187|    }
   188|    console.log();
   189|  }
   190|
   191|  private printSummary(
   192|    snapshot: { instruction?: string; fileSummary?: string; userProvidedHeader?: string },
   193|    options: CLIOptions
   194|  ): void {
   195|    if (options.json) {
   196|      const result: Record<string, string> = {};
   197|      if (snapshot.instruction) result.instruction = snapshot.instruction;
   198|      if (snapshot.fileSummary) result.fileSummary = snapshot.fileSummary;
   199|      if (snapshot.userProvidedHeader) result.userProvidedHeader = snapshot.userProvidedHeader;
   200|      this.print(result, options);
   201|      return;
   202|    }
   203|
   204|    if (snapshot.userProvidedHeader) {
   205|      console.log('\n📌 CUSTOM HEADER');
   206|      console.log('─'.repeat(40));
   207|      console.log(snapshot.userProvidedHeader);
   208|      console.log();
   209|    }
   210|
   211|    if (snapshot.fileSummary) {
   212|      console.log('\n📝 FILE SUMMARY');
   213|      console.log('─'.repeat(40));
   214|      console.log(snapshot.fileSummary);
   215|      console.log();
   216|    }
   217|
   218|    if (snapshot.instruction) {
   219|      console.log('\n💡 INSTRUCTIONS');
   220|      console.log('─'.repeat(40));
   221|      console.log(snapshot.instruction);
   222|      console.log();
   223|    }
   224|  }
   225|
   226|  private formatBytes(bytes: number): string {
   227|    if (bytes === 0) return '0 B';
   228|    const k = 1024;
   229|    const sizes = ['B', 'KB', 'MB', 'GB'];
   230|    const i = Math.floor(Math.log(bytes) / Math.log(k));
   231|    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
   232|  }
